import{_ as s,o as e,c as a,a5 as t}from"./chunks/framework.B5tqjWbr.js";const k=JSON.parse('{"title":"概念：单相全桥逆变器 LC 输出滤波","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：单相全桥逆变器 LC 输出滤波","tags":["power-electronics"],"status":"learning","summary":"单相全桥逆变器（single-phase full-bridge inverter）把直流母线（DC bus）的电压通过四个功率开关变成高频脉宽调制（pulse-width modulation / PWM）桥臂电压。LC 滤波器（inductor-capacitor filter / LC filter）再把高频开关"},"headers":[],"relativePath":"content/power/concepts/power-electronics/single-phase-inverter-lc-filter.md","filePath":"content/power/concepts/power-electronics/single-phase-inverter-lc-filter.md","lastUpdated":null}'),l={name:"content/power/concepts/power-electronics/single-phase-inverter-lc-filter.md"};function n(p,i,r,o,h,c){return e(),a("div",null,[...i[0]||(i[0]=[t(`<h1 id="概念-单相全桥逆变器-lc-输出滤波" tabindex="-1">概念：单相全桥逆变器 LC 输出滤波 <a class="header-anchor" href="#概念-单相全桥逆变器-lc-输出滤波" aria-label="Permalink to &quot;概念：单相全桥逆变器 LC 输出滤波&quot;">​</a></h1><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>单相全桥逆变器（single-phase full-bridge inverter）把直流母线（DC bus）的电压通过四个功率开关变成高频脉宽调制（pulse-width modulation / PWM）桥臂电压。LC 滤波器（inductor-capacitor filter / LC filter）再把高频开关分量压下去，让负载端看到接近 50 Hz 正弦的输出电压。</p><p>本节只讲一个概念：逆变器不是直接“生成干净正弦”，而是先生成高频 PWM 电压，再靠 LC 滤波器和控制环把目标基波保留下来。</p><p>保密边界：不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。本节只使用教学模型和教学参数，不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）在电池模式或双变换在线模式下，需要由直流母线向交流负载供电。逆变器负责把直流能量变成交流能量，LC 滤波器负责降低开关纹波，使输出电压满足负载和电能质量要求。</p><p>如果只理解控制器而不理解 LC 滤波器，你读固件时会看不懂为什么要采样输出电压、电感电流、直流母线电压，也不容易判断“波形畸变”到底来自调制、滤波器参数、负载还是控制环。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>全桥桥臂电压像一个高速来回切换的方波，平均值跟随 50 Hz 正弦参考。电感电流（inductor current / iL）不能突变，所以电感会阻挡高频电压突变；电容电压也不能突变，所以电容会把负载端电压变得平滑。二者组合后，高频 PWM 纹波被大幅衰减，低频 50 Hz 基波被保留下来。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>教学模型使用双极性全桥 PWM：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>m*sin(2*pi*f_out*t) 与三角载波比较</span></span>
<span class="line"><span>v_bridge = +Vdc 或 -Vdc</span></span>
<span class="line"><span></span></span>
<span class="line"><span>diL/dt = (v_bridge - v_out) / L</span></span>
<span class="line"><span>dv_out/dt = (iL - v_out/Rload) / C</span></span>
<span class="line"><span>f_res = 1 / (2*pi*sqrt(L*C))</span></span></code></pre></div><p>其中 <code>m</code> 是调制比。若全桥双极性输出在 <code>+Vdc</code> 和 <code>-Vdc</code> 之间切换，理想基波峰值约为 <code>m*Vdc</code>，所以 220 Vrms 输出在 400 V 母线下需要约 <code>m = 220*sqrt(2)/400</code>。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_inverter_lc_filter.py</span></span></code></pre></div><p>观察顺序：</p><ul><li><code>v_bridge</code> 是高频 PWM 方波，不是干净正弦。</li><li><code>v_out</code> 是 LC 滤波后的输出电压，应接近 <code>v_ref</code>。</li><li><code>i_L</code> 反映滤波器和负载之间的能量交换。</li><li><code>Output switching ripple</code> 是从输出电压中扣掉 50 Hz 基波后的高频残差。</li></ul><p>脚本默认保存并自动打开图片；如果无法自动打开，会打印完整图片路径。</p><p>一个仿真任务：改变滤波电感，观察输出纹波、电感电流峰值和 LC 谐振频率的变化。</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_inverter_lc_filter.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">filter</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">inductance </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.0e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\inverter_lc_L_1p0mH.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_inverter_lc_filter.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">filter</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">inductance </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.5e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\inverter_lc_L_2p5mH.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>固件里常见的数据流是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ADC samples</span></span>
<span class="line"><span>  -&gt; Vdc, Vout, iL scaling/filtering</span></span>
<span class="line"><span>  -&gt; sine reference or PLL angle</span></span>
<span class="line"><span>  -&gt; voltage loop / current loop</span></span>
<span class="line"><span>  -&gt; PWM compare update</span></span>
<span class="line"><span>  -&gt; protection checks</span></span></code></pre></div><p>本节先不进入比例谐振（proportional resonant / PR）控制和均方根（root mean square / RMS）闭环，只要求你能把桥臂 PWM、电感电流、输出电压和 LC 参数联系起来。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li>错误理解：逆变器直接输出正弦电压。<br> 正确理解：功率级先输出 PWM 电压，滤波器和控制环让负载端接近正弦。</li><li>错误理解：LC 截止频率越低越好。<br> 正确理解：太低会增加体积、相位滞后和动态问题；太高又滤不掉开关纹波。</li><li>错误理解：只要输出 RMS 接近 220 V 就说明波形好。<br> 正确理解：还要看纹波、谐波、瞬态、负载变化和保护边界。</li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能解释 <code>v_bridge</code>、<code>v_out</code>、<code>v_ref</code>、<code>i_L</code> 分别代表什么。</li><li>能说出为什么 LC 滤波器能压低开关纹波，但不会凭空决定输出基波幅值。</li><li>能根据图内参数框读出 Vdc、Vout_ref、f_out、f_sw、L、C、Rload、f_res 和 t_end。</li><li>能解释为什么桥臂纹波 RMS 明显大于输出纹波 RMS。</li><li>能基于 <code>single_phase_inverter_lc_filter.py</code> 生成的仿真图准备导师问题。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>400 V 直流母线下，要输出 220 Vrms，调制比为什么接近 0.778？</li><li>如果把电感从 1.0 mH 增大到 2.5 mH，输出纹波和电感电流峰值会怎样变化？代价是什么？</li><li>为什么 LC 谐振频率不能离 50 Hz 太近，也不能太靠近 10 kHz 开关频率？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>我用 <code>single_phase_inverter_lc_filter.py</code> 看到桥臂 PWM 纹波远大于输出纹波。公司 UPS 固件通常会同时采样 <code>Vout</code> 和 <code>iL</code> 吗？各自主要用于控制还是保护？</li><li>仿真里 <code>L=1.80 mH</code>、<code>C=20.00 uF</code> 时 <code>f_res</code> 约为几百 Hz。真实产品选择 LC 参数时，通常先看开关频率、体积、动态响应还是保护裕量？</li><li>如果输出电压 RMS 正常但 <code>Output switching ripple</code> 偏大，真实调试时优先怀疑滤波器参数、PWM 死区、采样噪声还是控制环带宽？</li></ul>`,34)])])}const u=s(l,[["render",n]]);export{k as __pageData,u as default};
